#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        N++;
        while (1) {
            char str[20];
            sprintf(str, "%d", N);
            int count = 0;
            for (int i = 0; i < strlen(str) - 2; i++) {
                if (str[i] == '3' && str[i+1] == '3' && str[i+2] == '3') {
                    count++;
                }
            }
            if (count >= 3) {
                printf("%d\n", N);
                break;
            }
            N++;
        }
    }
    return 0;
}

