        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            N++;
            while (true) {
                String str = Integer.toString(N);
                int count = 0;
                for (int i = 0; i < str.length() - 2; i++) {
                    if (str.charAt(i) == '3' && str.charAt(i+1) == '3' && str.charAt(i+2) == '3') {
                        count++;
                    }
                }
                if (count >= 3) {
                    System.out.println(N);
                    break;
                }
                N++;
            }
        }
    }
}

